"""
MKT Matthew chapters 1-7 — three-tier translation written directly to draft JSON files.
Run: python3 scripts/mkt-matthew-1-7.py
"""
import json, pathlib

ROOT  = pathlib.Path(__file__).parent.parent
DRAFT = ROOT / 'data' / 'translation' / 'draft'

def load(tier, book):
    p = DRAFT / tier / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save(tier, book, data):
    p = DRAFT / tier / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

MATTHEW = {
 "1": {
  "1": {"L":"The book of the genealogy of Jesus Christ, son of David, son of Abraham.","M":"The record of the genealogy of Jesus Christ, son of David, son of Abraham.","T":"This is the family record of Jesus the Messiah, a descendant of David and Abraham."},
  "2": {"L":"Abraham begat Isaac, and Isaac begat Jacob, and Jacob begat Judah and his brothers.","M":"Abraham was the father of Isaac, Isaac the father of Jacob, Jacob the father of Judah and his brothers.","T":"Abraham was the father of Isaac, Isaac of Jacob, and Jacob of Judah and his brothers."},
  "3": {"L":"And Judah begat Perez and Zerah by Tamar, and Perez begat Hezron, and Hezron begat Ram.","M":"Judah was the father of Perez and Zerah by Tamar, Perez the father of Hezron, Hezron the father of Ram.","T":"Judah fathered Perez and Zerah through Tamar; Perez fathered Hezron; Hezron fathered Ram."},
  "4": {"L":"And Ram begat Amminadab, and Amminadab begat Nahshon, and Nahshon begat Salmon.","M":"Ram the father of Amminadab, Amminadab the father of Nahshon, Nahshon the father of Salmon.","T":"Ram fathered Amminadab; Amminadab fathered Nahshon; Nahshon fathered Salmon."},
  "5": {"L":"And Salmon begat Boaz by Rahab, and Boaz begat Obed by Ruth, and Obed begat Jesse.","M":"Salmon the father of Boaz by Rahab, Boaz the father of Obed by Ruth, Obed the father of Jesse.","T":"Salmon fathered Boaz through Rahab; Boaz fathered Obed through Ruth; Obed fathered Jesse."},
  "6": {"L":"And Jesse begat David the king. And David begat Solomon by her who had been the wife of Uriah.","M":"Jesse the father of David the king. David the father of Solomon by the wife of Uriah.","T":"Jesse fathered King David. David fathered Solomon, whose mother had been Uriah's wife."},
  "7": {"L":"And Solomon begat Rehoboam, and Rehoboam begat Abijah, and Abijah begat Asa.","M":"Solomon the father of Rehoboam, Rehoboam the father of Abijah, Abijah the father of Asa.","T":"Solomon fathered Rehoboam; Rehoboam fathered Abijah; Abijah fathered Asa."},
  "8": {"L":"And Asa begat Jehoshaphat, and Jehoshaphat begat Joram, and Joram begat Uzziah.","M":"Asa the father of Jehoshaphat, Jehoshaphat the father of Joram, Joram the father of Uzziah.","T":"Asa fathered Jehoshaphat; Jehoshaphat fathered Joram; Joram fathered Uzziah."},
  "9": {"L":"And Uzziah begat Jotham, and Jotham begat Ahaz, and Ahaz begat Hezekiah.","M":"Uzziah the father of Jotham, Jotham the father of Ahaz, Ahaz the father of Hezekiah.","T":"Uzziah fathered Jotham; Jotham fathered Ahaz; Ahaz fathered Hezekiah."},
  "10": {"L":"And Hezekiah begat Manasseh, and Manasseh begat Amos, and Amos begat Josiah.","M":"Hezekiah the father of Manasseh, Manasseh the father of Amos, Amos the father of Josiah.","T":"Hezekiah fathered Manasseh; Manasseh fathered Amos; Amos fathered Josiah."},
  "11": {"L":"And Josiah begat Jechoniah and his brothers at the deportation to Babylon.","M":"Josiah the father of Jechoniah and his brothers at the time of the exile to Babylon.","T":"Josiah fathered Jechoniah and his brothers at the time of the Babylonian exile."},
  "12": {"L":"And after the deportation to Babylon, Jechoniah begat Shealtiel, and Shealtiel begat Zerubbabel.","M":"After the exile to Babylon, Jechoniah was the father of Shealtiel, Shealtiel the father of Zerubbabel.","T":"After the Babylonian exile: Jechoniah fathered Shealtiel; Shealtiel fathered Zerubbabel."},
  "13": {"L":"And Zerubbabel begat Abiud, and Abiud begat Eliakim, and Eliakim begat Azor.","M":"Zerubbabel the father of Abiud, Abiud the father of Eliakim, Eliakim the father of Azor.","T":"Zerubbabel fathered Abiud; Abiud fathered Eliakim; Eliakim fathered Azor."},
  "14": {"L":"And Azor begat Zadok, and Zadok begat Achim, and Achim begat Eliud.","M":"Azor the father of Zadok, Zadok the father of Achim, Achim the father of Eliud.","T":"Azor fathered Zadok; Zadok fathered Achim; Achim fathered Eliud."},
  "15": {"L":"And Eliud begat Eleazar, and Eleazar begat Matthan, and Matthan begat Jacob.","M":"Eliud the father of Eleazar, Eleazar the father of Matthan, Matthan the father of Jacob.","T":"Eliud fathered Eleazar; Eleazar fathered Matthan; Matthan fathered Jacob."},
  "16": {"L":"And Jacob begat Joseph the husband of Mary, from whom was born Jesus, who is called Christ.","M":"Jacob the father of Joseph, the husband of Mary, by whom Jesus was born, who is called Christ.","T":"Jacob fathered Joseph, the husband of Mary. Mary gave birth to Jesus, who is called the Messiah."},
  "17": {"L":"So all the generations from Abraham to David are fourteen generations, and from David until the deportation to Babylon fourteen generations, and from the deportation to Babylon until Christ fourteen generations.","M":"Thus all the generations from Abraham to David are fourteen, from David to the deportation to Babylon are fourteen, and from the deportation to Babylon to Christ are fourteen.","T":"In all, from Abraham to David is fourteen generations; from David to the Babylonian exile, fourteen more; and from the exile to the Messiah, fourteen more."},
  "18": {"L":"Now the birth of Jesus Christ was thus: his mother Mary having been betrothed to Joseph, before they came together she was found to be with child of the Holy Spirit.","M":"This is how the birth of Jesus Christ came about: his mother Mary was pledged to be married to Joseph, but before they came together, she was found to be pregnant through the Holy Spirit.","T":"The birth of Jesus the Messiah took place in this way: his mother Mary was engaged to Joseph, but before they were married, it was discovered that she was pregnant—through the Holy Spirit."},
  "19": {"L":"And Joseph her husband, being righteous and not willing to expose her publicly, purposed to dismiss her secretly.","M":"Joseph her husband was a righteous man and did not want to disgrace her publicly, so he planned to divorce her quietly.","T":"Joseph, to whom she was engaged, was an honorable man. Rather than humiliate her publicly, he planned to break off the engagement privately."},
  "20": {"L":"But while he was pondering these things, behold, an angel of the Lord appeared to him in a dream, saying: Joseph, son of David, do not fear to take Mary your wife, for that which has been conceived in her is of the Holy Spirit.","M":"But as he was considering this, an angel of the Lord appeared to him in a dream and said: Joseph, son of David, do not be afraid to take Mary as your wife, because what is conceived in her is from the Holy Spirit.","T":"As Joseph was thinking all this through, God's angel appeared to him in a dream and said: Joseph, heir of David, don't be afraid to marry Mary—the child she carries was conceived by the Holy Spirit."},
  "21": {"L":"She will bear a son, and you shall call his name Jesus, for he will save his people from their sins.","M":"She will give birth to a son, and you are to give him the name Jesus, because he will save his people from their sins.","T":"She will have a son, and you are to name him Jesus—because he will rescue his people from the power of sin."},
  "22": {"L":"Now all this came to pass that it might be fulfilled which was spoken by the Lord through the prophet, saying:","M":"All this took place to fulfil what the Lord had said through the prophet:","T":"All of this happened to bring to completion what God had spoken through the prophet:"},
  "23": {"L":"Behold, the virgin shall be with child and shall bear a son, and they shall call his name Emmanuel, which being translated is God with us.","M":"The virgin will conceive and give birth to a son, and they will call him Immanuel—which means God with us.","T":"The virgin will become pregnant and give birth to a son, and they will name him Immanuel—a name that means God is with us."},
  "24": {"L":"Then Joseph, rising from sleep, did as the angel of the Lord had commanded him and took his wife.","M":"When Joseph woke up, he did what the angel of the Lord had commanded him and took Mary as his wife.","T":"Joseph woke from sleep and did exactly what God's angel had told him to do—he took Mary as his wife."},
  "25": {"L":"And he did not know her until she had borne a son; and he called his name Jesus.","M":"But he had no marital relations with her until she gave birth to a son; and he named him Jesus.","T":"He did not sleep with her until she had given birth to her son. And he named the child Jesus."}
 },
 "2": {
  "1": {"L":"Now after Jesus was born in Bethlehem of Judea in the days of Herod the king, behold, Magi from the east came to Jerusalem,","M":"After Jesus was born in Bethlehem in Judea, during the time of King Herod, Magi from the east arrived in Jerusalem","T":"Jesus was born in Bethlehem in the Judean territory, during the reign of King Herod. Not long after, astrologers from the east arrived in Jerusalem"},
  "2": {"L":"saying: Where is the one born King of the Jews? For we saw his star in its rising and have come to worship him.","M":"and asked: Where is the one who has been born King of the Jews? We saw his star when it rose and have come to worship him.","T":"and asked: Where is the newborn King of the Jews? We saw his star rise and have traveled here to honor him."},
  "3": {"L":"And hearing this, Herod the king was troubled, and all Jerusalem with him.","M":"When King Herod heard this, he was deeply disturbed, and all Jerusalem with him.","T":"News of this threw King Herod into alarm, and the whole city of Jerusalem along with him."},
  "4": {"L":"And gathering together all the chief priests and scribes of the people, he inquired of them where Christ was to be born.","M":"When he had gathered all the chief priests and teachers of the law, he asked them where the Messiah was to be born.","T":"He called together all the chief priests and religious scholars and demanded to know where the Messiah was supposed to be born."},
  "5": {"L":"And they said to him: In Bethlehem of Judea; for thus it is written by the prophet:","M":"In Bethlehem in Judea, they replied, for this is what the prophet has written:","T":"In Bethlehem in Judea, they answered, because that is what the prophet recorded:"},
  "6": {"L":"And you, Bethlehem, land of Judah, are by no means least among the rulers of Judah; for from you shall come forth a ruler who will shepherd my people Israel.","M":"But you, Bethlehem, in the land of Judah, are by no means the least among the rulers of Judah; for from you will come a ruler who will be the shepherd of my people Israel.","T":"Bethlehem in the land of Judah, you are far from insignificant among the leading cities of Judah—for a ruler will emerge from you who will be the shepherd-king of my people Israel."},
  "7": {"L":"Then Herod, having secretly called the Magi, carefully inquired from them the time the star had appeared.","M":"Then Herod called the Magi secretly and found out from them the exact time the star had appeared.","T":"Herod then secretly summoned the astrologers and questioned them carefully about the precise time the star had appeared."},
  "8": {"L":"And sending them to Bethlehem, he said: Go and search carefully for the child; and when you have found him, report to me so that I also may come and worship him.","M":"He sent them to Bethlehem and said: Go and search carefully for the child. As soon as you find him, report to me, so that I too may go and worship him.","T":"He sent them on to Bethlehem with these instructions: Go and make a thorough search for the child. When you find him, come back and tell me—I want to come and honor him myself."},
  "9": {"L":"And having heard the king, they departed; and behold, the star which they had seen in its rising went before them until it came and stood over the place where the child was.","M":"After they had heard the king, they set out, and the star they had seen when it rose went ahead of them until it stopped over the place where the child was.","T":"They set out as the king instructed. And the star they had seen rise reappeared, leading them forward until it stopped and hovered over the exact place where the child was."},
  "10": {"L":"And seeing the star, they rejoiced with very great joy.","M":"When they saw the star, they were overjoyed.","T":"The sight of the star filled them with overwhelming joy."},
  "11": {"L":"And coming into the house they saw the child with Mary his mother, and falling down they worshipped him; then opening their treasure-chests they offered him gifts: gold and frankincense and myrrh.","M":"On coming to the house, they saw the child with his mother Mary, and they bowed down and worshipped him. Then they opened their treasures and presented him with gifts of gold, frankincense and myrrh.","T":"They entered the house and saw the child with Mary his mother. They fell to the ground and worshipped him, then opened their gift-boxes and presented him with gold, fragrant incense, and myrrh."},
  "12": {"L":"And being warned by God in a dream not to return to Herod, they departed to their own country by another way.","M":"And having been warned in a dream not to go back to Herod, they returned to their country by another route.","T":"They had been warned in a dream not to report back to Herod, so they returned home by a different road."},
  "13": {"L":"Now after they had departed, behold, an angel of the Lord appeared to Joseph in a dream, saying: Arise, take the child and his mother and flee to Egypt, and remain there until I tell you; for Herod is about to seek the child to destroy him.","M":"When they had gone, an angel of the Lord appeared to Joseph in a dream. Get up, he said, take the child and his mother and escape to Egypt. Stay there until I tell you, for Herod is going to search for the child to kill him.","T":"After the astrologers had left, God's angel appeared to Joseph in a dream: Get up now—take the child and his mother and flee to Egypt. Stay there until I give you word, because Herod is hunting for the child to have him killed."},
  "14": {"L":"And rising, he took the child and his mother by night and withdrew to Egypt,","M":"So he got up, took the child and his mother during the night and left for Egypt,","T":"Joseph got up that same night, took the child and his mother, and set off for Egypt."},
  "15": {"L":"and was there until the death of Herod, that it might be fulfilled which was spoken by the Lord through the prophet: Out of Egypt I called my son.","M":"where he stayed until the death of Herod. And so was fulfilled what the Lord had said through the prophet: Out of Egypt I called my son.","T":"They stayed there until Herod died. This brought to fulfillment what God had spoken through the prophet: Out of Egypt I summoned my son."},
  "16": {"L":"Then Herod, seeing that he had been mocked by the Magi, was exceedingly angry, and sending forth he slew all the male children in Bethlehem and in all its borders, from two years old and under, according to the time which he had carefully inquired from the Magi.","M":"When Herod realized that he had been outwitted by the Magi, he was furious, and he gave orders to kill all the boys in Bethlehem and its vicinity who were two years old and under, in accordance with the time he had learned from the Magi.","T":"When Herod realized the astrologers had outmaneuvered him, his rage was volcanic. He ordered the slaughter of every male child in Bethlehem and the surrounding region who was two years old or younger—using the date of the star's appearance that he had so carefully extracted from the astrologers."},
  "17": {"L":"Then was fulfilled what was spoken through Jeremiah the prophet, saying:","M":"Then what was said through the prophet Jeremiah was fulfilled:","T":"This fulfilled the words spoken through the prophet Jeremiah:"},
  "18": {"L":"A voice was heard in Ramah, weeping and great lamentation: Rachel weeping for her children, and she refused to be comforted, because they are no more.","M":"A voice is heard in Ramah, weeping and great mourning, Rachel weeping for her children and refusing to be comforted, because they are no more.","T":"A voice echoed from Ramah—weeping, bitter anguish. Rachel weeping for her children, refusing any comfort, because they were gone."},
  "19": {"L":"But when Herod died, behold, an angel of the Lord appeared in a dream to Joseph in Egypt, saying:","M":"After Herod died, an angel of the Lord appeared in a dream to Joseph in Egypt","T":"When Herod finally died, God's angel appeared to Joseph in a dream while he was still in Egypt."},
  "20": {"L":"Arise, take the child and his mother and go to the land of Israel; for those seeking the life of the child have died.","M":"and said: Get up, take the child and his mother and go to the land of Israel, for those who were trying to take the child's life are dead.","T":"The angel said: Get up, take the child and his mother back to the land of Israel—the men who wanted the child dead are themselves now dead."},
  "21": {"L":"And rising, he took the child and his mother and entered the land of Israel.","M":"So he got up, took the child and his mother and went to the land of Israel.","T":"Joseph got up, took the child and his mother, and returned to the land of Israel."},
  "22": {"L":"But hearing that Archelaus was reigning over Judea in place of his father Herod, he was afraid to go there; and being warned in a dream he withdrew into the region of Galilee.","M":"But when he heard that Archelaus was reigning in Judea in place of his father Herod, he was afraid to go there. Having been warned in a dream, he withdrew to the district of Galilee,","T":"But when he learned that Archelaus had taken his father Herod's place as ruler over Judea, Joseph was afraid to go there. Directed by another dream, he rerouted to the region of Galilee instead."},
  "23": {"L":"and coming he dwelt in a city called Nazareth, so that what was spoken through the prophets might be fulfilled: He shall be called a Nazarene.","M":"and he went and lived in a town called Nazareth. So was fulfilled what was said through the prophets, that he would be called a Nazarene.","T":"He settled in a town called Nazareth—bringing to fulfillment what the prophets had said, that he would be called a Nazarene."}
 },
 "3": {
  "1": {"L":"And in those days comes John the Baptist, preaching in the wilderness of Judea,","M":"In those days John the Baptist came, preaching in the Desert of Judea","T":"In that period, John the Baptizer appeared, preaching in the Judean wilderness."},
  "2": {"L":"saying: Repent, for the kingdom of heaven has drawn near.","M":"and saying: Repent, for the kingdom of heaven has come near.","T":"His message was direct: Turn back to God—the heavenly reign is arriving now."},
  "3": {"L":"For this is the one spoken of through Isaiah the prophet, saying: A voice of one crying in the wilderness: Prepare the way of the Lord, make his paths straight.","M":"This is he who was spoken of through the prophet Isaiah: A voice of one calling in the desert, Prepare the way for the Lord, make straight paths for him.","T":"Isaiah the prophet had described him centuries earlier: A voice calling out in the desert—Clear the road for the Lord, straighten the path before him!"},
  "4": {"L":"Now John himself had his clothing of camel's hair and a leather belt about his waist; and his food was locusts and wild honey.","M":"John's clothes were made of camel's hair, and he had a leather belt around his waist. His food was locusts and wild honey.","T":"John's clothing was camel-hair fabric with a leather belt at his waist. He ate locusts and wild honey."},
  "5": {"L":"Then there went out to him Jerusalem and all Judea and all the region about the Jordan,","M":"People went out to him from Jerusalem and all Judea and the whole region of the Jordan.","T":"People streamed out to him from Jerusalem, from all over Judea, and from the whole Jordan valley."},
  "6": {"L":"and they were baptized by him in the Jordan River, confessing their sins.","M":"Confessing their sins, they were baptized by him in the Jordan River.","T":"They confessed their sins and were baptized by him in the Jordan."},
  "7": {"L":"But seeing many of the Pharisees and Sadducees coming to his baptism, he said to them: You offspring of vipers! Who warned you to flee from the coming wrath?","M":"But when he saw many of the Pharisees and Sadducees coming to where he was baptizing, he said to them: You brood of vipers! Who warned you to flee from the coming wrath?","T":"When John saw a crowd of Pharisees and Sadducees arriving for baptism, he confronted them: You snake-spawn! Who tipped you off to run from the coming judgment?"},
  "8": {"L":"Bear fruit therefore worthy of repentance,","M":"Produce fruit in keeping with repentance.","T":"Show by the way you live that you've genuinely turned around."},
  "9": {"L":"and do not think to say within yourselves: We have Abraham as father; for I tell you that God is able from these stones to raise up children to Abraham.","M":"And do not think you can say to yourselves: We have Abraham as our father. I tell you that out of these stones God can raise up children for Abraham.","T":"Don't console yourselves by saying: But we're Abraham's descendants. I'm telling you, God could turn these stones into Abraham's children if he wanted."},
  "10": {"L":"And now also the axe is laid to the root of the trees; every tree therefore not bearing good fruit is hewn down and cast into the fire.","M":"The axe is already at the root of the trees, and every tree that does not produce good fruit will be cut down and thrown into the fire.","T":"The axe is already positioned at the base of the trees. Every tree that fails to produce good fruit will be chopped down and tossed into the fire."},
  "11": {"L":"I indeed baptize you with water for repentance, but the one coming after me is mightier than I, whose sandals I am not worthy to carry. He will baptize you in the Holy Spirit and fire;","M":"I baptize you with water for repentance. But after me comes one who is more powerful than I, whose sandals I am not worthy to carry. He will baptize you with the Holy Spirit and fire.","T":"I baptize you with water as a sign of turning to God. But the one coming after me is far more powerful than I am—I'm not even worthy to carry his sandals. He will baptize you with the Holy Spirit and with fire."},
  "12": {"L":"whose winnowing fork is in his hand, and he will thoroughly cleanse his threshing floor and gather his wheat into the barn, but the chaff he will burn with unquenchable fire.","M":"His winnowing fork is in his hand, and he will clear his threshing floor, gathering his wheat into the barn and burning up the chaff with unquenchable fire.","T":"He comes with his threshing fork ready. He will separate the grain from the husks, storing the wheat and burning the chaff in a fire that cannot be put out."},
  "13": {"L":"Then comes Jesus from Galilee to the Jordan, to John, to be baptized by him.","M":"Then Jesus came from Galilee to the Jordan to be baptized by John.","T":"At that time Jesus came from Galilee to the Jordan River to be baptized by John."},
  "14": {"L":"But John tried to prevent him, saying: I have need to be baptized by you, and do you come to me?","M":"But John tried to deter him, saying: I need to be baptized by you, and do you come to me?","T":"John tried to stop him: You should be baptizing me—why are you coming to me?"},
  "15": {"L":"But Jesus answering said to him: Permit it now; for thus it is fitting for us to fulfil all righteousness. Then he permitted him.","M":"Jesus replied: Let it be so now; it is proper for us to do this to fulfil all righteousness. Then John consented.","T":"Jesus answered: Let it happen now—this is the right thing to do to bring all that God requires to completion. John agreed."},
  "16": {"L":"And being baptized, Jesus immediately went up from the water; and behold, the heavens were opened to him, and he saw the Spirit of God descending as a dove, and coming upon him.","M":"As soon as Jesus was baptized, he went up out of the water. At that moment heaven was opened, and he saw the Spirit of God descending like a dove and alighting on him.","T":"As Jesus rose from the water, the sky suddenly opened and he saw God's Spirit descending on him in the form of a dove."},
  "17": {"L":"And behold, a voice out of the heavens, saying: This is my Son, the Beloved, in whom I am well pleased.","M":"And a voice from heaven said: This is my Son, whom I love; with him I am well pleased.","T":"And a voice from heaven declared: This is my Son, the one I cherish—he brings me great joy."}
 },
 "4": {
  "1": {"L":"Then Jesus was led up by the Spirit into the wilderness to be tempted by the devil.","M":"Then Jesus was led by the Spirit into the desert to be tempted by the devil.","T":"The Spirit then led Jesus out into the wilderness to be tested by the devil."},
  "2": {"L":"And having fasted forty days and forty nights, afterward he was hungry.","M":"After fasting forty days and forty nights, he was hungry.","T":"After forty days and nights without food, he was famished."},
  "3": {"L":"And coming, the tempter said to him: If you are the Son of God, speak so that these stones become bread.","M":"The tempter came to him and said: If you are the Son of God, tell these stones to become bread.","T":"The tempter approached and said: If you really are the Son of God, order these rocks to turn into bread."},
  "4": {"L":"But he answering said: It is written: Man shall not live on bread alone, but on every word proceeding out of the mouth of God.","M":"Jesus answered: It is written: Man shall not live on bread alone, but on every word that comes from the mouth of God.","T":"Jesus replied: Scripture says, Human beings don't live on food alone—they live on every word that comes from God."},
  "5": {"L":"Then the devil took him into the holy city and set him upon the pinnacle of the temple,","M":"Then the devil took him to the holy city and had him stand on the highest point of the temple.","T":"Next the devil transported him to the holy city of Jerusalem and positioned him on the highest point of the temple."},
  "6": {"L":"and says to him: If you are the Son of God, cast yourself down; for it is written: He will command his angels concerning you, and on their hands they will bear you up, lest you strike your foot against a stone.","M":"If you are the Son of God, he said, throw yourself down. For it is written: He will command his angels concerning you, and they will lift you up in their hands, so that you will not strike your foot against a stone.","T":"The devil said: If you truly are the Son of God, jump off—because Scripture says God will order his angels to catch you, and they'll hold you up so you don't even stub your toe on a stone."},
  "7": {"L":"Jesus said to him: Again it is written: You shall not tempt the Lord your God.","M":"Jesus answered him: It is also written: Do not put the Lord your God to the test.","T":"Jesus responded: But Scripture also says, Don't put God to a foolish test."},
  "8": {"L":"Again, the devil takes him to a very high mountain and shows him all the kingdoms of the world and their glory;","M":"Again, the devil took him to a very high mountain and showed him all the kingdoms of the world and their splendour.","T":"For the final test, the devil took him to the summit of a towering mountain and displayed before him every kingdom in the world in all its splendour."},
  "9": {"L":"and he said to him: All these things I will give you, if you will fall down and worship me.","M":"All this I will give you, he said, if you will bow down and worship me.","T":"I'll give all of this to you, the devil said, if you'll simply kneel down and worship me."},
  "10": {"L":"Then Jesus says to him: Be gone, Satan! For it is written: You shall worship the Lord your God, and him only shall you serve.","M":"Jesus said to him: Away from me, Satan! For it is written: Worship the Lord your God, and serve him only.","T":"Jesus replied sharply: Get away from me, Satan! Scripture says, Worship and serve God alone."},
  "11": {"L":"Then the devil left him; and behold, angels came and ministered to him.","M":"Then the devil left him, and angels came and attended him.","T":"The devil left, and angels came and cared for him."},
  "12": {"L":"Now having heard that John had been delivered up, he withdrew into Galilee.","M":"When Jesus heard that John had been put in prison, he withdrew to Galilee.","T":"When Jesus learned that John had been arrested, he pulled back to Galilee."},
  "13": {"L":"And leaving Nazareth, he came and dwelt in Capernaum, which is beside the sea, in the regions of Zebulun and Naphtali;","M":"Leaving Nazareth, he went and lived in Capernaum, which was by the lake in the area of Zebulun and Naphtali—","T":"He left Nazareth and settled in Capernaum, a lakeside town in the territory of Zebulun and Naphtali."},
  "14": {"L":"that it might be fulfilled which was spoken through Isaiah the prophet, saying:","M":"to fulfil what was said through the prophet Isaiah:","T":"This fulfilled what Isaiah the prophet had written:"},
  "15": {"L":"Land of Zebulun and land of Naphtali, the way of the sea, beyond the Jordan, Galilee of the Gentiles—","M":"Land of Zebulun and land of Naphtali, the Way of the Sea, beyond the Jordan, Galilee of the Gentiles—","T":"The territory of Zebulun and Naphtali, along the Sea road, east of the Jordan—Galilee of the nations—"},
  "16": {"L":"the people sitting in darkness have seen a great light, and upon those sitting in the region and shadow of death, light has dawned.","M":"the people living in darkness have seen a great light; on those living in the land of the shadow of death a light has dawned.","T":"the people who sat in deep darkness have seen a blazing light; on those entombed in the region of death's shadow, light has burst forth."},
  "17": {"L":"From that time Jesus began to preach and to say: Repent, for the kingdom of heaven has drawn near.","M":"From that time on Jesus began to preach: Repent, for the kingdom of heaven has come near.","T":"From that point on, Jesus began proclaiming the same message: Turn back to God—the heavenly reign is arriving now."},
  "18": {"L":"And walking by the Sea of Galilee, he saw two brothers, Simon called Peter and Andrew his brother, casting a net into the sea, for they were fishermen.","M":"As Jesus was walking beside the Sea of Galilee, he saw two brothers, Simon called Peter and his brother Andrew. They were casting a net into the lake, for they were fishermen.","T":"As he walked along the shore of the Sea of Galilee, Jesus spotted two brothers—Simon, known as Peter, and his brother Andrew—throwing a fishing net into the water."},
  "19": {"L":"And he says to them: Come after me, and I will make you fishers of men.","M":"Come, follow me, Jesus said, and I will send you out to fish for people.","T":"Jesus called out to them: Come, follow me, and I'll make you fishers of people."},
  "20": {"L":"And immediately leaving the nets, they followed him.","M":"At once they left their nets and followed him.","T":"Without hesitation they abandoned their nets and went with him."},
  "21": {"L":"And going on from there, he saw two other brothers, James the son of Zebedee and John his brother, in the boat with their father Zebedee, mending their nets; and he called them.","M":"Going on from there, he saw two other brothers, James son of Zebedee and his brother John. They were in a boat with their father Zebedee, preparing their nets. Jesus called them,","T":"A little further along the shore he saw another pair of brothers—James and John, the sons of Zebedee—sitting in their boat with their father, repairing their nets. Jesus called to them."},
  "22": {"L":"And immediately leaving the boat and their father, they followed him.","M":"and immediately they left the boat and their father and followed him.","T":"They immediately left the boat and their father and followed him."},
  "23": {"L":"And he went about in all Galilee, teaching in their synagogues and proclaiming the gospel of the kingdom and healing every disease and every infirmity among the people.","M":"Jesus went throughout Galilee, teaching in their synagogues, proclaiming the good news of the kingdom, and healing every disease and sickness among the people.","T":"Jesus traveled all through Galilee, teaching in the synagogues, announcing the good news of God's reign, and healing every kind of illness and disability among the people."},
  "24": {"L":"And the report about him went out through all Syria; and they brought to him all those who were ill, those afflicted with various diseases and torments, demon-possessed, and epileptics, and paralytics; and he healed them.","M":"News about him spread all over Syria, and people brought to him all who were ill with various diseases, those suffering severe pain, the demon-possessed, those having seizures, and the paralysed, and he healed them.","T":"Word about him spread throughout Syria, and people started bringing him all their sick—those suffering from painful diseases, the demon-possessed, those with seizure disorders, and paralyzed people—and he healed every one of them."},
  "25": {"L":"And great multitudes followed him from Galilee and Decapolis and Jerusalem and Judea and from beyond the Jordan.","M":"Large crowds from Galilee, the Decapolis, Jerusalem, Judea and the region across the Jordan followed him.","T":"Enormous crowds began following him from Galilee, the Ten-City region, Jerusalem, Judea, and from the far side of the Jordan."}
 },
 "5": {
  "1": {"L":"And seeing the crowds, he went up on the mountain; and when he sat down, his disciples came to him.","M":"Now when Jesus saw the crowds, he went up on a mountainside and sat down. His disciples came to him,","T":"Seeing the crowds gathering, Jesus climbed the hillside and sat down. His disciples gathered around him,"},
  "2": {"L":"And opening his mouth he taught them, saying:","M":"and he began to teach them. He said:","T":"and he began to teach them."},
  "3": {"L":"Blessed are the poor in spirit, for theirs is the kingdom of heaven.","M":"Blessed are the poor in spirit, for theirs is the kingdom of heaven.","T":"Those who know their spiritual poverty are favored by God—the heavenly kingdom belongs to them."},
  "4": {"L":"Blessed are those who mourn, for they shall be comforted.","M":"Blessed are those who mourn, for they will be comforted.","T":"Those who grieve and weep are favored by God—they will receive deep comfort."},
  "5": {"L":"Blessed are the meek, for they shall inherit the earth.","M":"Blessed are the meek, for they will inherit the earth.","T":"Those who are gentle and humble are favored by God—they will inherit the whole earth."},
  "6": {"L":"Blessed are those who hunger and thirst for righteousness, for they shall be satisfied.","M":"Blessed are those who hunger and thirst for righteousness, for they will be filled.","T":"Those who are hungry and thirsty for what is right are favored by God—their longing will be satisfied."},
  "7": {"L":"Blessed are the merciful, for they shall obtain mercy.","M":"Blessed are the merciful, for they will be shown mercy.","T":"Those who show compassion are favored by God—they will receive compassion in return."},
  "8": {"L":"Blessed are the pure in heart, for they shall see God.","M":"Blessed are the pure in heart, for they will see God.","T":"Those with undivided, sincere hearts are favored by God—they will see God himself."},
  "9": {"L":"Blessed are the peacemakers, for they shall be called sons of God.","M":"Blessed are the peacemakers, for they will be called children of God.","T":"Those who actively make peace are favored by God—they will be recognized as his children."},
  "10": {"L":"Blessed are those who have been persecuted for righteousness' sake, for theirs is the kingdom of heaven.","M":"Blessed are those who are persecuted because of righteousness, for theirs is the kingdom of heaven.","T":"Those who face opposition for doing what is right are favored by God—the heavenly kingdom belongs to them."},
  "11": {"L":"Blessed are you when men revile you and persecute you and say every evil thing against you falsely on account of me.","M":"Blessed are you when people insult you, persecute you and falsely say all kinds of evil against you because of me.","T":"You are favored by God when people insult you, chase you off, and lie about you because of your connection to me."},
  "12": {"L":"Rejoice and be exceeding glad, for great is your reward in heaven; for so they persecuted the prophets who were before you.","M":"Rejoice and be glad, because great is your reward in heaven, for in the same way they persecuted the prophets who were before you.","T":"Celebrate—jump for joy! Your reward in heaven is enormous. Remember, the prophets before you were treated just the same way."},
  "13": {"L":"You are the salt of the earth; but if the salt loses its savour, by what means shall it be salted? It is no longer good for anything, except to be cast out and to be trodden under foot of men.","M":"You are the salt of the earth. But if the salt loses its saltiness, how can it be made salty again? It is no longer good for anything, except to be thrown out and trampled underfoot.","T":"You are the earth's salt. But if salt goes flat, what can possibly make it salty again? It becomes useless—only fit to be thrown out and stepped on."},
  "14": {"L":"You are the light of the world. A city situated upon a hill cannot be hidden.","M":"You are the light of the world. A town built on a hill cannot be hidden.","T":"You are the world's light. A city on a hilltop can't be concealed."},
  "15": {"L":"Nor do they light a lamp and put it under the bushel, but upon the lampstand, and it shines upon all who are in the house.","M":"Neither do people light a lamp and put it under a bowl. Instead they put it on its stand, and it gives light to everyone in the house.","T":"Nobody lights a lamp and covers it with a bucket—they put it on a stand where it lights the whole room."},
  "16": {"L":"Even so, let your light shine before men, that they may see your good works and glorify your Father who is in heaven.","M":"In the same way, let your light shine before others, that they may see your good deeds and glorify your Father in heaven.","T":"In the same way, let your light blaze before people so they can see the good you do and praise your Father in heaven."},
  "17": {"L":"Do not suppose that I came to abolish the law or the prophets; I did not come to abolish but to fulfil.","M":"Do not think that I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfil them.","T":"Don't assume I've come to tear down the Law and the Prophets—I came not to demolish them but to bring them to complete fulfilment."},
  "18": {"L":"For verily I say to you, until heaven and earth pass away, one iota or one tittle shall in no wise pass from the law until all be accomplished.","M":"For truly I tell you, until heaven and earth disappear, not the smallest letter, not the least stroke of a pen, will by any means disappear from the Law until everything is accomplished.","T":"I'm telling you plainly: not the smallest letter or punctuation mark in the Law will disappear before heaven and earth are gone and everything it points to has come to pass."},
  "19": {"L":"Whosoever therefore shall break one of these least commandments, and shall teach men so, shall be called least in the kingdom of heaven: but whosoever shall do and teach them, he shall be called great in the kingdom of heaven.","M":"Therefore anyone who sets aside one of the least of these commands and teaches others accordingly will be called least in the kingdom of heaven, but whoever practises and teaches these commands will be called great in the kingdom of heaven.","T":"So whoever dismisses even the smallest of these commands—and teaches others to do the same—will hold the lowest position in God's kingdom. But those who keep them and teach them will hold the highest."},
  "20": {"L":"For I say to you that unless your righteousness shall exceed the righteousness of the scribes and Pharisees, ye shall in no wise enter into the kingdom of heaven.","M":"For I tell you that unless your righteousness surpasses that of the Pharisees and the teachers of the law, you will certainly not enter the kingdom of heaven.","T":"Let me be direct with you: unless the way you live is far more genuinely righteous than that of the Pharisees and religious scholars, you will not enter God's kingdom at all."},
  "21": {"L":"You have heard that it was said to those of old: You shall not murder; and whoever commits murder shall be liable to the judgment.","M":"You have heard that it was said to the people long ago: You shall not murder, and anyone who murders will be subject to judgment.","T":"You've been taught the ancient command: Don't commit murder; and murderers must face the court."},
  "22": {"L":"But I say to you that everyone who is angry with his brother shall be liable to the judgment; and whoever says to his brother Raca shall be liable to the council; but whoever says You fool! shall be liable to the hell of fire.","M":"But I tell you that anyone who is angry with a brother or sister will be subject to judgment. Again, anyone who says to a brother or sister Raca is answerable to the court. And anyone who says You fool! will be in danger of the fire of hell.","T":"But I'm going further: anyone who nurses resentment against a fellow human is already in danger of judgment. Calling someone worthless makes you answerable before the religious council. And calling someone a fool puts you in danger of the fire of Gehenna."},
  "23": {"L":"If therefore you bring your gift to the altar and there remember that your brother has something against you,","M":"Therefore, if you are offering your gift at the altar and there remember that your brother or sister has something against you,","T":"So if you're bringing your offering to the altar and you suddenly remember that someone has a grievance against you,"},
  "24": {"L":"leave your gift there before the altar and go; first be reconciled to your brother, and then come and offer your gift.","M":"leave your gift there in front of the altar. First go and be reconciled to them; then come and offer your gift.","T":"leave your offering right there at the altar and go make things right with that person first. Then come back and give your offering."},
  "25": {"L":"Be making friends with your adversary quickly, while you are with him on the road; lest the adversary hand you over to the judge, and the judge to the officer, and you be cast into prison.","M":"Settle matters quickly with your adversary who is taking you to court. Do it while you are still together on the way, or your adversary may hand you over to the judge, and the judge may hand you over to the officer, and you may be thrown into prison.","T":"Settle things fast with anyone who has a legal case against you while you're still on the way to court—otherwise they'll hand you to the judge, who'll hand you to the bailiff, and you'll end up in prison."},
  "26": {"L":"Verily I say to you, you will by no means come out from there until you have paid the last penny.","M":"Truly I tell you, you will not get out until you have paid the last penny.","T":"I promise you, you won't get out until you've paid every last cent."},
  "27": {"L":"You have heard that it was said: You shall not commit adultery.","M":"You have heard that it was said: You shall not commit adultery.","T":"You know the commandment: Don't commit adultery."},
  "28": {"L":"But I say to you that everyone who looks at a woman with desire after her has already committed adultery with her in his heart.","M":"But I tell you that anyone who looks at a woman lustfully has already committed adultery with her in his heart.","T":"But I'm taking it further: anyone who deliberately looks at a woman with sexual desire has already committed adultery with her at the level of the heart."},
  "29": {"L":"And if your right eye causes you to stumble, pluck it out and cast it from you; for it is profitable for you that one of your members perish and not your whole body be cast into hell.","M":"If your right eye causes you to stumble, gouge it out and throw it away. It is better for you to lose one part of your body than for your whole body to be thrown into hell.","T":"If your right eye is leading you into sin, gouge it out and throw it away—it's far better to lose one body part than for your whole self to end up in Gehenna."},
  "30": {"L":"And if your right hand causes you to stumble, cut it off and cast it from you; for it is profitable for you that one of your members perish and not your whole body go into hell.","M":"And if your right hand causes you to stumble, cut it off and throw it away. It is better for you to lose one part of your body than for your whole body to go into hell.","T":"If your right hand is leading you into sin, cut it off and throw it away—better to lose a hand than for your whole self to end up in Gehenna."},
  "31": {"L":"It was also said: Whoever puts away his wife, let him give her a certificate of divorce.","M":"It has been said: Anyone who divorces his wife must give her a certificate of divorce.","T":"The old rule was: Anyone who sends his wife away must give her a proper divorce document."},
  "32": {"L":"But I say to you that everyone who puts away his wife, except for the cause of fornication, causes her to commit adultery; and whoever marries a divorced woman commits adultery.","M":"But I tell you that anyone who divorces his wife, except for sexual immorality, makes her the victim of adultery, and anyone who marries a divorced woman commits adultery.","T":"But I say this: anyone who divorces his wife—unless she has been sexually unfaithful—exposes her to adultery. And anyone who marries a woman so divorced commits adultery."},
  "33": {"L":"Again, you have heard that it was said to those of old: You shall not swear falsely, but shall perform to the Lord your oaths.","M":"Again, you have heard that it was said to the people long ago: Do not break your oath, but fulfil to the Lord the vows you have made.","T":"You've also heard the ancient teaching: Don't break your oaths—follow through on whatever you've vowed to God."},
  "34": {"L":"But I say to you: swear not at all; neither by heaven, for it is the throne of God;","M":"But I tell you: Do not swear an oath at all: either by heaven, for it is God's throne;","T":"But my instruction is this: don't take oaths at all—not by heaven, which is God's throne;"},
  "35": {"L":"nor by the earth, for it is his footstool; nor by Jerusalem, for it is the city of the great King.","M":"or by the earth, for it is his footstool; or by Jerusalem, for it is the city of the Great King.","T":"not by the earth, which is his footstool; not by Jerusalem, which is the great King's city."},
  "36": {"L":"Nor shalt thou swear by your head, for you cannot make one hair white or black.","M":"And do not swear by your head, for you cannot make even one hair white or black.","T":"Don't even swear by your own head—you can't make a single hair white or black."},
  "37": {"L":"But let your speech be: Yea, yea; Nay, nay; and whatever is more than these is of the evil one.","M":"All you need to say is simply Yes or No; anything beyond this comes from the evil one.","T":"Just say yes when you mean yes, and no when you mean no. Anything more elaborate comes from the deceiver."},
  "38": {"L":"You have heard that it was said: An eye for an eye and a tooth for a tooth.","M":"You have heard that it was said: Eye for eye, and tooth for tooth.","T":"You know the principle: An eye for an eye, a tooth for a tooth."},
  "39": {"L":"But I say to you: Do not resist the evil one; but whoever strikes you on your right cheek, turn to him the other also.","M":"But I tell you, do not resist an evil person. If anyone slaps you on the right cheek, turn to them the other cheek also.","T":"But I'm overturning that: don't meet force with force. If someone strikes you on the right cheek, offer the other one as well."},
  "40": {"L":"And to him who would take you to law and take your tunic, let him have your cloak also.","M":"And if anyone wants to sue you and take your shirt, hand over your coat as well.","T":"If someone drags you to court to take your shirt, give them your coat too."},
  "41": {"L":"And whoever shall compel you to go one mile, go with him two.","M":"If anyone forces you to go one mile, go with them two miles.","T":"If a soldier commands you to carry his pack a mile, carry it two."},
  "42": {"L":"Give to the one asking you, and do not turn away from the one who wishes to borrow from you.","M":"Give to the one who asks you, and do not turn away from the one who wants to borrow from you.","T":"Give to those who ask, and don't turn away those who want to borrow from you."},
  "43": {"L":"You have heard that it was said: You shall love your neighbor and hate your enemy.","M":"You have heard that it was said: Love your neighbour and hate your enemy.","T":"You've heard the teaching: Love your neighbor—and hate your enemy."},
  "44": {"L":"But I say to you: Love your enemies and pray for those who persecute you;","M":"But I tell you: Love your enemies and pray for those who persecute you,","T":"But my instruction is radically different: Love your enemies. Pray for the people who target you."},
  "45": {"L":"that you may be sons of your Father who is in heaven; for he makes his sun rise on the evil and the good, and sends rain on the just and the unjust.","M":"that you may be children of your Father in heaven. He causes his sun to rise on the evil and the good, and sends rain on the righteous and the unrighteous.","T":"This is how you will show you are children of your Father in heaven—because he lets the sun shine on both good and evil people, and sends rain on both the righteous and unrighteous alike."},
  "46": {"L":"For if you love those who love you, what reward have you? Do not even the tax collectors the same?","M":"If you love those who love you, what reward will you get? Are not even the tax collectors doing that?","T":"What's so remarkable about loving people who already love you? Even tax collectors do that much."},
  "47": {"L":"And if you salute your brethren only, what do you more than others? Do not even the Gentiles the same?","M":"And if you greet only your own people, what are you doing more than others? Do not even pagans do that?","T":"And if you're friendly only to your own circle, what sets you apart? Even outsiders do that."},
  "48": {"L":"You shall therefore be perfect, as your heavenly Father is perfect.","M":"Be perfect, therefore, as your heavenly Father is perfect.","T":"Grow into the complete goodness of your heavenly Father."}
 },
 "6": {
  "1": {"L":"Take heed not to do your righteousness before men, to be seen by them; otherwise you have no reward from your Father who is in heaven.","M":"Be careful not to practise your righteousness in front of others to be seen by them. If you do, you will have no reward from your Father in heaven.","T":"Watch out—don't put your acts of devotion on display for others to admire. If you do, you earn nothing from your Father in heaven."},
  "2": {"L":"When therefore you give alms, do not sound a trumpet before you, as the hypocrites do in the synagogues and in the streets, that they may have glory from men. Verily I say to you, They have their reward.","M":"So when you give to the needy, do not announce it with trumpets, as the hypocrites do in the synagogues and on the streets, to be honoured by others. Truly I tell you, they have received their reward in full.","T":"So when you give to those in need, don't make a fanfare of it the way pretenders do in the synagogues and on the street corners—performing for public admiration. That admiration is all the reward they're ever going to get."},
  "3": {"L":"But when you give alms, let not your left hand know what your right hand does;","M":"But when you give to the needy, do not let your left hand know what your right hand is doing,","T":"But when you give, do it so privately that your left hand doesn't know what your right hand is doing."},
  "4": {"L":"that your alms may be in secret; and your Father who sees in secret shall reward you.","M":"so that your giving may be in secret. Then your Father, who sees what is done in secret, will reward you.","T":"Keep your generosity hidden, and your Father who observes what is hidden will reward you."},
  "5": {"L":"And when you pray, you shall not be as the hypocrites; for they love to stand and pray in the synagogues and in the corners of the streets, that they may be seen of men. Verily I say to you, They have their reward.","M":"And when you pray, do not be like the hypocrites, for they love to pray standing in the synagogues and on the street corners to be seen by others. Truly I tell you, they have received their reward in full.","T":"And when you pray, don't perform the way pretenders do—they love to stand praying in synagogues and on street corners where everyone can see them. That public attention is all they're going to get."},
  "6": {"L":"But you, when you pray, enter into your inner room, and shutting your door, pray to your Father who is in secret; and your Father who sees in secret shall reward you.","M":"But when you pray, go into your room, close the door and pray to your Father, who is unseen. Then your Father, who sees what is done in secret, will reward you.","T":"Instead, go to a private place, close the door, and pray to your Father who is there in the hidden place. Your Father who sees the hidden will reward you."},
  "7": {"L":"And in praying do not use vain repetitions, as the Gentiles do; for they think that they shall be heard for their much speaking.","M":"And when you pray, do not keep on babbling like pagans, for they think they will be heard because of their many words.","T":"When you pray, don't pile up words the way pagans do—they think the more they say, the better the chance God will hear them."},
  "8": {"L":"Therefore be not like them; for your Father knows what things you have need of before you ask him.","M":"Do not be like them, for your Father knows what you need before you ask him.","T":"Don't imitate them. Your Father already knows what you need before you ask."},
  "9": {"L":"After this manner therefore pray: Our Father who art in heaven, hallowed be thy name.","M":"This, then, is how you should pray: Our Father in heaven, hallowed be your name,","T":"This is the pattern for your prayer: Our Father in heaven—may your name be held holy,"},
  "10": {"L":"Thy kingdom come. Thy will be done, as in heaven, so on earth.","M":"your kingdom come, your will be done, on earth as it is in heaven.","T":"may your reign arrive, your will be done on earth just as it is in heaven."},
  "11": {"L":"Give us this day our daily bread.","M":"Give us today our daily bread.","T":"Provide for our needs today."},
  "12": {"L":"And forgive us our debts, as we also have forgiven our debtors.","M":"And forgive us our debts, as we also have forgiven our debtors.","T":"Forgive us our wrongs, as we have forgiven those who have wronged us."},
  "13": {"L":"And lead us not into temptation, but deliver us from the evil one. For thine is the kingdom, and the power, and the glory, forever. Amen.","M":"And lead us not into temptation, but deliver us from the evil one. For yours is the kingdom and the power and the glory, forever. Amen.","T":"And keep us from being pulled toward wrongdoing; rescue us from the evil one. For the kingdom, the power, and the glory belong to you forever. Amen."},
  "14": {"L":"For if you forgive men their trespasses, your heavenly Father will also forgive you.","M":"For if you forgive other people when they sin against you, your heavenly Father will also forgive you.","T":"Because if you forgive others for what they've done against you, your heavenly Father will forgive you too."},
  "15": {"L":"But if you forgive not men their trespasses, neither will your Father forgive your trespasses.","M":"But if you do not forgive others their sins, your Father will not forgive your sins.","T":"But if you refuse to forgive others, your Father will not forgive what you've done either."},
  "16": {"L":"Moreover when you fast, be not as the hypocrites, of a sad countenance; for they disfigure their faces that they may appear unto men to fast. Verily I say to you, They have their reward.","M":"When you fast, do not look sombre as the hypocrites do, for they disfigure their faces to show others they are fasting. Truly I tell you, they have received their reward in full.","T":"When you fast, don't make yourself look miserable the way pretenders do—they make their faces haggard so everyone will know they're fasting. That public recognition is their full reward."},
  "17": {"L":"But when you fast, anoint your head and wash your face;","M":"But when you fast, put oil on your head and wash your face,","T":"Instead, when you fast, wash your face and fix your hair as usual."},
  "18": {"L":"that you appear not unto men to fast, but unto your Father who is in secret; and your Father who sees in secret shall reward you.","M":"so that it will not be obvious to others that you are fasting, but only to your Father, who is unseen; and your Father, who sees what is done in secret, will reward you.","T":"Then your fast is between you and your Father in the hidden place—not a performance for others. And your Father who sees what is hidden will reward you."},
  "19": {"L":"Lay not up for yourselves treasures upon the earth, where moth and rust consume, and where thieves break through and steal;","M":"Do not store up for yourselves treasures on earth, where moths and vermin destroy, and where thieves break in and steal.","T":"Stop stockpiling wealth for yourself here on earth, where moths eat it, rust corrodes it, and thieves can break in and take it."},
  "20": {"L":"but lay up for yourselves treasures in heaven, where neither moth nor rust doth consume, and where thieves do not break through nor steal;","M":"But store up for yourselves treasures in heaven, where moths and vermin do not destroy, and where thieves do not break in and steal.","T":"Instead, build up wealth in heaven, where moths can't touch it, rust can't erode it, and no thief can reach it."},
  "21": {"L":"for where your treasure is, there will your heart be also.","M":"For where your treasure is, there your heart will be also.","T":"Your heart will always follow your treasure."},
  "22": {"L":"The lamp of the body is the eye; if therefore your eye be single, your whole body shall be full of light.","M":"The eye is the lamp of the body. If your eyes are healthy, your whole body will be full of light.","T":"The eye is the body's lamp. If your vision is clear and focused, your whole inner life will be bright."},
  "23": {"L":"But if your eye be evil, your whole body shall be full of darkness. If therefore the light that is in you is darkness, how great is the darkness!","M":"But if your eyes are unhealthy, your whole body will be full of darkness. If then the light within you is darkness, how great is that darkness!","T":"But if your vision is distorted or corrupt, your whole inner life will be darkened. If what you call light is actually darkness, what profound darkness that must be."},
  "24": {"L":"No man can serve two masters; for either he will hate the one and love the other, or else he will hold to one and despise the other. Ye cannot serve God and mammon.","M":"No one can serve two masters. Either you will hate the one and love the other, or you will be devoted to the one and despise the other. You cannot serve both God and Money.","T":"You can't serve two masters at once—you'll end up loving one and resenting the other, or loyal to one and contemptuous of the other. You simply cannot divide your allegiance between God and Wealth."},
  "25": {"L":"Therefore I say unto you, Take no thought for your life, what ye shall eat, or what ye shall drink; nor yet for your body, what ye shall put on. Is not the life more than meat, and the body than raiment?","M":"Therefore I tell you, do not worry about your life, what you will eat or drink; or about your body, what you will wear. Is not life more than food, and the body more than clothes?","T":"So I'm telling you: stop being anxious about the basics of survival—food and drink and clothing. Isn't there more to life than what you eat? Isn't your body about more than what you wear?"},
  "26": {"L":"Behold the birds of the heaven, that they sow not, neither do they reap, nor gather into barns; and your heavenly Father feeds them. Are not ye of much more value than they?","M":"Look at the birds of the air; they do not sow or reap or store away in barns, and yet your heavenly Father feeds them. Are you not much more valuable than they?","T":"Watch the birds—they don't plant, harvest, or store grain in warehouses, yet your heavenly Father feeds them all. And you matter far more to God than birds do."},
  "27": {"L":"And which of you by being anxious can add one cubit to his stature?","M":"Can any one of you by worrying add a single hour to your life?","T":"Besides, which of you has ever extended his life by one hour through worrying?"},
  "28": {"L":"And why take ye thought for raiment? Consider the lilies of the field, how they grow; they toil not, neither do they spin;","M":"And why do you worry about clothes? See how the flowers of the field grow. They do not labour or spin.","T":"And why fret over clothing? Look carefully at the wildflowers—they don't work or weave."},
  "29": {"L":"yet I say unto you, that even Solomon in all his glory was not arrayed like one of these.","M":"Yet I tell you that not even Solomon in all his splendour was dressed like one of these.","T":"Yet I'm telling you, even Solomon in the peak of his glory was never dressed as beautifully as one of them."},
  "30": {"L":"But if God so clothes the grass of the field, which today is and tomorrow is cast into the oven, will he not much more clothe you, O you of little faith?","M":"If that is how God clothes the grass of the field, which is here today and tomorrow is thrown into the fire, will he not much more clothe you—you of little faith?","T":"If God dresses the grass of the field that way—and it's here today and burnt up tomorrow—don't you think he'll certainly clothe you? How little you trust him!"},
  "31": {"L":"Be not therefore anxious, saying: What shall we eat? or, What shall we drink? or, Wherewithal shall we be clothed?","M":"So do not worry, saying: What shall we eat? or What shall we drink? or What shall we wear?","T":"So stop asking: What will we eat? What will we drink? What will we wear?"},
  "32": {"L":"For after all these things do the Gentiles seek; for your heavenly Father knows that ye have need of all these things.","M":"For the pagans run after all these things, and your heavenly Father knows that you need them.","T":"These are the things that dominate the lives of those who don't know God. But your heavenly Father already knows you need all of them."},
  "33": {"L":"But seek ye first his kingdom and his righteousness; and all these things shall be added unto you.","M":"But seek first his kingdom and his righteousness, and all these things will be given to you as well.","T":"Instead, make God's reign and his way of living your top priority—and all these other things will be provided for you."},
  "34": {"L":"Be not therefore anxious for the morrow; for the morrow shall be anxious for itself. Sufficient unto the day is the evil thereof.","M":"Therefore do not worry about tomorrow, for tomorrow will worry about itself. Each day has enough trouble of its own.","T":"So don't borrow tomorrow's worries today. Tomorrow will bring its own challenges. Today's challenges are enough to deal with."}
 },
 "7": {
  "1": {"L":"Judge not, that ye be not judged.","M":"Do not judge, or you too will be judged.","T":"Stop sitting in judgment over others, or you will find yourself judged."},
  "2": {"L":"For with what judgment ye judge, ye shall be judged; and with what measure ye mete, it shall be measured unto you.","M":"For in the same way you judge others, you will be judged, and with the measure you use, it will be measured to you.","T":"The standard you apply to others will be applied right back to you—the measuring stick you use on others is the one that will be used on you."},
  "3": {"L":"And why do you behold the splinter that is in your brother's eye, but do not perceive the beam that is in your own eye?","M":"Why do you look at the speck of sawdust in your brother's eye and pay no attention to the plank in your own eye?","T":"Why are you so focused on the tiny speck in your friend's eye when you have a beam of timber in your own?"},
  "4": {"L":"Or how wilt thou say to thy brother: Let me cast out the splinter from thine eye; and lo, the beam is in thine own eye?","M":"How can you say to your brother: Let me take the speck out of your eye, when all the time there is a plank in your own eye?","T":"How dare you say to your friend: Here, let me remove that speck from your eye—while you have a plank in your own?"},
  "5": {"L":"Thou hypocrite, cast out first the beam out of thine own eye; and then shalt thou see clearly to cast out the splinter out of thy brother's eye.","M":"You hypocrite, first take the plank out of your own eye, and then you will see clearly to remove the speck from your brother's eye.","T":"You are the hypocrite here. Deal with the plank in your own eye first—then you'll see clearly enough to help with the speck in your friend's."},
  "6": {"L":"Give not that which is holy unto the dogs, neither cast your pearls before the swine, lest haply they trample them under their feet, and turn and rend you.","M":"Do not give dogs what is sacred; do not throw your pearls to pigs. If you do, they may trample them under their feet, and turn and tear you to pieces.","T":"Don't offer sacred things to those who will only despise them. Don't throw your pearls in front of pigs—they'll just trample them and then turn and attack you."},
  "7": {"L":"Ask, and it shall be given you; seek, and ye shall find; knock, and it shall be opened unto you;","M":"Ask and it will be given to you; seek and you will find; knock and the door will be opened to you.","T":"Ask and you will receive. Search and you will find. Knock and the door will open."},
  "8": {"L":"for every one that asketh receiveth; and he that seeketh findeth; and to him that knocketh it shall be opened.","M":"For everyone who asks receives; the one who seeks finds; and to the one who knocks, the door will be opened.","T":"Everyone who asks receives; everyone who searches finds; and for everyone who knocks, the door is opened."},
  "9": {"L":"Or what man is there of you, who, if his son shall ask him for a loaf, will give him a stone?","M":"Which of you, if your son asks for bread, will give him a stone?","T":"Think about it—is there a parent among you who, when their child asks for bread, would hand them a stone?"},
  "10": {"L":"or if he shall ask for a fish, will give him a serpent?","M":"Or if he asks for a fish, will give him a snake?","T":"Or when they ask for fish, give them a snake?"},
  "11": {"L":"If ye then, being evil, know how to give good gifts unto your children, how much more shall your Father who is in heaven give good things to them that ask him?","M":"If you, then, though you are evil, know how to give good gifts to your children, how much more will your Father in heaven give good gifts to those who ask him!","T":"If you flawed, broken people know how to give your children what's good for them, imagine how much more your Father in heaven will give good things to those who ask him."},
  "12": {"L":"All things therefore whatsoever ye would that men should do unto you, even so do ye also unto them; for this is the law and the prophets.","M":"So in everything, do to others what you would have them do to you, for this sums up the Law and the Prophets.","T":"Here is the principle that holds everything together: treat others the way you want them to treat you. This is the heart of all Scripture."},
  "13": {"L":"Enter ye in by the narrow gate; for wide is the gate, and broad is the way, that leadeth to destruction, and many are they that enter in thereby.","M":"Enter through the narrow gate. For wide is the gate and broad is the road that leads to destruction, and many enter through it.","T":"Go in through the narrow gate. The wide gate with the easy road leads to destruction—and crowds of people take that route."},
  "14": {"L":"For narrow is the gate, and straitened the way, that leadeth unto life, and few are they that find it.","M":"But small is the gate and narrow the road that leads to life, and only a few find it.","T":"But the gate that leads to real life is narrow and the path demanding—and only a few ever find it."},
  "15": {"L":"Beware of false prophets, who come to you in sheep's clothing, but inwardly are ravening wolves.","M":"Watch out for false prophets. They come to you in sheep's clothing, but inwardly they are ferocious wolves.","T":"Watch out for fraudulent prophets. They come looking perfectly respectable, but underneath they are predators."},
  "16": {"L":"By their fruits ye shall know them. Do men gather grapes of thorns, or figs of thistles?","M":"By their fruit you will recognise them. Do people pick grapes from thornbushes, or figs from thistles?","T":"Their track record will expose them. You don't harvest grapes from thorn-bushes or figs from thistles, do you?"},
  "17": {"L":"Even so every good tree bringeth forth good fruit; but the corrupt tree bringeth forth evil fruit.","M":"Likewise, every good tree bears good fruit, but a bad tree bears bad fruit.","T":"A healthy tree produces good fruit; a diseased tree produces bad fruit."},
  "18": {"L":"A good tree cannot bring forth evil fruit, neither can a corrupt tree bring forth good fruit.","M":"A good tree cannot bear bad fruit, and a bad tree cannot bear good fruit.","T":"A healthy tree is incapable of producing bad fruit, just as a diseased tree can't produce good fruit."},
  "19": {"L":"Every tree that bringeth not forth good fruit is hewn down, and cast into the fire.","M":"Every tree that does not bear good fruit is cut down and thrown into the fire.","T":"Every tree that fails to produce good fruit gets cut down and thrown into the fire."},
  "20": {"L":"Therefore by their fruits ye shall know them.","M":"Thus, by their fruit you will recognise them.","T":"So yes—their track record is how you'll recognize them."},
  "21": {"L":"Not every one that saith unto me, Lord, Lord, shall enter into the kingdom of heaven; but he that doeth the will of my Father who is in heaven.","M":"Not everyone who says to me: Lord, Lord, will enter the kingdom of heaven, but only the one who does the will of my Father who is in heaven.","T":"Not everyone who calls out to me Lord, Lord will enter God's kingdom—only those who actually do what my Father in heaven requires."},
  "22": {"L":"Many will say to me in that day: Lord, Lord, did we not prophesy by thy name, and by thy name cast out demons, and by thy name do many mighty works?","M":"Many will say to me on that day: Lord, Lord, did we not prophesy in your name and in your name drive out demons and in your name perform many miracles?","T":"On the day of judgment many people will say to me: But Lord, we prophesied in your name! We drove out demons in your name! We performed all kinds of miracles in your name!"},
  "23": {"L":"And then will I profess unto them: I never knew you; depart from me, ye that work iniquity.","M":"Then I will tell them plainly: I never knew you. Away from me, you evildoers!","T":"And I will say clearly: I never had a relationship with you. Get away from me—you who lived lawlessly."},
  "24": {"L":"Everyone therefore who heareth these words of mine, and doeth them, shall be likened unto a wise man, who built his house upon the rock.","M":"Therefore everyone who hears these words of mine and puts them into practice is like a wise man who built his house on the rock.","T":"So everyone who hears what I've said here and puts it into practice is like a wise builder who laid his foundation on solid rock."},
  "25": {"L":"And the rain descended, and the floods came, and the winds blew, and beat upon that house; and it fell not; for it was founded upon the rock.","M":"The rain came down, the streams rose, and the winds blew and beat against that house; yet it did not fall, because it had its foundation on the rock.","T":"The rains poured down, the floodwaters rose, and the storms battered that house—but it didn't collapse because its foundation was on solid rock."},
  "26": {"L":"And every one that heareth these words of mine, and doeth them not, shall be likened unto a foolish man, who built his house upon the sand.","M":"But everyone who hears these words of mine and does not put them into practice is like a foolish man who built his house on sand.","T":"But everyone who hears what I've said and doesn't act on it is like a foolish builder who laid his foundation on sand."},
  "27": {"L":"And the rain descended, and the floods came, and the winds blew, and smote upon that house; and it fell: and great was the fall thereof.","M":"The rain came down, the streams rose, and the winds blew and beat against that house, and it fell with a great crash.","T":"When the rains poured, the floods rose, and the storms hit that house, it collapsed—completely and catastrophically."},
  "28": {"L":"And it came to pass, when Jesus ended these words, the multitudes were astonished at his teaching;","M":"When Jesus had finished saying these things, the crowds were amazed at his teaching,","T":"When Jesus finished this discourse, the crowds were stunned by his teaching."},
  "29": {"L":"for he taught them as one having authority, and not as their scribes.","M":"because he taught as one who had authority, and not as their teachers of the law.","T":"He spoke with genuine authority—nothing like the religious scholars they were used to."}
 }
}

def main():
    for tier, key in (('literal','L'), ('mediating','M'), ('thought','T')):
        data = load(tier, 'matthew')
        for ch, verses in MATTHEW.items():
            data[ch] = {v: d[key] for v, d in verses.items()}
        save(tier, 'matthew', data)
    print('Matthew chapters 1-7 written.')

if __name__ == '__main__':
    main()
